export interface ResgateResponse {
  status: {
    message: string;
  };
  data?: {
    status: string;
  };
}

export interface RescuePayload {
  value: number;
  campaignId?: string;
  productCode?: string;
  description: string;
  participantId?: string;
}

export enum RescueStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

