  reset: () => void;
}

export interface RescueApiResponse {
  status: {
    message: string;
  };
  data?: {
    status: string;
  };
}

export type RescueCallbacks = {
  onSuccess?: (status: ResgateResponse['status']) => void;
  onFailed?: (status?: ResgateResponse['status']) => void;
};

