     2→import { useCallback, useEffect, useMemo } from 'react';
     3→import { KEY_NAME_TO_ICON, NAME_TO_ICON, getNormalizedKeyName } from '../../../screens/Points/data';
     4→import { PointsProduct } from '../../../redux/ducks/points';
     5→import { PointsCardItem } from '../../../screens/Points/Models';
     6→import { usePermission } from '../../../services';
     7→import { extractRawProducts, isValidProduct, normalizeName } from './data';
     8→import { PointsCardItemBuilder } from './data/pointsCardItemBuilder';
     9→import { PropsRootStack } from '../../../routes/Models';
    10→import { eventSelectContent } from '~/constants/functions';
    11→
    12→export const useCardBuilderWhereUseMyPoints = () => {
    13→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    14→  const { checkHasRedeemed } = usePermission();
    15→
    16→  useEffect(() => {
    17→    checkHasRedeemed().catch(() => {});
    18→  }, [checkHasRedeemed]);
    19→
    20→  const onPressKeyName = useMemo(
    21→    () => ({
    22→      [normalizeName(KEY_NAME_TO_ICON.MARKETPLACE)]: () => {
    23→        navigation.navigate('RewardProgramMarketplace');
    24→      },
    25→      [normalizeName(KEY_NAME_TO_ICON.FUEL_VOUCHER)]: () => {},
    26→      [normalizeName(KEY_NAME_TO_ICON.MONTHLY_DISCOUNT)]: () => {},
    27→      [normalizeName(KEY_NAME_TO_ICON.CAR_INSURANCE_DISCOUNT)]: () => {},
    28→      [normalizeName(KEY_NAME_TO_ICON.PARKING_DISCOUNT)]: () => {},
    29→      [normalizeName(KEY_NAME_TO_ICON.FINES_DISCOUNT)]: () => {},
    30→      [normalizeName(KEY_NAME_TO_ICON.IPVA_DISCOUNT)]: () => {},
    31→      [normalizeName(KEY_NAME_TO_ICON.AIRLINE_MILES)]: () => {
    32→        navigation.navigate('AirlineMilesMarketplace');
    33→      },
    34→    }),
    35→    [navigation]
    36→  );
    37→
    38→  const handleOnPress = useCallback(
    39→    (keyName: string) => {
    40→      return () => {
    41→        if (keyName in onPressKeyName) {
    42→          onPressKeyName[keyName]();
    43→          const contentIdName = getNormalizedKeyName(keyName).split(' ').join('_').toLowerCase();
    44→
    45→          eventSelectContent({
    46→            content_type: 'cta',
    47→            content_id: `onde_usar_${contentIdName}`,
    48→            location_1: 'monetizacao',
    49→            location_2: 'hub_recompensas_spmais',
    50→            location_3: 'home_hub_recompensas',
    51→          });
    52→        }
    53→      };
    54→    },
    55→    [onPressKeyName]
    56→  );
    57→
    58→  const buildPointsCardItems = useCallback(
    59→    (pointsOptions: PointsProduct[] | undefined): PointsCardItem[] => {
    60→      const rawProducts = extractRawProducts(pointsOptions);
    61→      const builder = PointsCardItemBuilder.getInstance();
    62→
    63→      return rawProducts.filter(isValidProduct).map((product, index) => {
    64→        const normalizedName = normalizeName(product.name);
    65→        const icon = NAME_TO_ICON[normalizedName] || 'icon-default';
    66→
    67→        const isCashbackInInvoice =
    68→          normalizedName === normalizeName(KEY_NAME_TO_ICON.RESCUE_IN_INVOICE);
    69→        const onPress = isCashbackInInvoice
    70→          ? async () => {
    71→              eventSelectContent({
    72→                content_type: 'cta',
    73→                content_id: `onde_usar_cashback_na_fatura`,
    74→                location_1: 'monetizacao',
    75→                location_2: 'hub_recompensas_spmais',
    76→                location_3: 'home_hub_recompensas',
    77→              })
    78→              const rawCF =
    79→                (product as any).conversionFactor ?? (product as any).convertionFactor ?? 0;
    80→              const conversionFactor = (() => {
    81→                if (typeof rawCF === 'number') return rawCF;
    82→                if (typeof rawCF === 'string') {
    83→                  const n = Number(
    84→                    String(rawCF)
    85→                      .replace(',', '.')
    86→                      .replace(/[^0-9.-]/g, '')
    87→                  );
    88→                  return Number.isFinite(n) ? n : 0;
    89→                }
    90→                return 0;
    91→              })();
    92→              const productCode = (product as any).productCode ?? (product as any).code;
    93→              const campaingId =
    94→                (product as any).campaingId ?? (product as any).campaignId ?? undefined;
    95→
    96→            const hasRedeemed = await checkHasRedeemed();
    97→            if (hasRedeemed) {
    98→                navigation.navigate('InvoiceCashbackPoints', {
    99→                  conversionFactor,
   100→                  productCode,
   101→                  campaingId,
   102→                });
   103→              } else {
   104→                navigation.navigate('InvoiceCashbackOnboarding', {
   105→                  conversionFactor,
   106→                  productCode,
   107→                  campaingId,
   108→                });
   109→              }
   110→          }
   111→          : handleOnPress(normalizedName);
   112→
   113→        return builder
   114→          .reset()
   115→          .setId(index + 1)
   116→          .setText(product.name)
   117→          .setIcon(icon)
   118→          .setOnPress(onPress)
   119→          .build();
   120→      });
   121→    },
   122→    [handleOnPress, checkHasRedeemed, navigation]
   123→  );
   124→
   125→  return buildPointsCardItems;
   126→};
